def _join_param_hints(param_hint: cabc.Sequence[str] | str | None) -> str | None:
    if param_hint is not None and not isinstance(param_hint, str):
        return " / ".join(repr(x) for x in param_hint)

    return param_hint


def _format_possibilities(possibilities: list[str]) -> str:
    possibility_str = ", ".join(repr(p) for p in sorted(possibilities))
    return ngettext(
        "Did you mean {possibility}?",
        "(Did you mean one of: {possibilities}?)",
        len(possibilities),
    ).format(possibility=possibility_str, possibilities=possibility_str)

def __init__(self, *args: object, **kwargs: object) -> None:
        from pandas.errors import Pandas4Warning

        warnings.warn(
            "Substitution is deprecated and will be removed in a future version.",
            Pandas4Warning,
            stacklevel=find_stack_level(),
        )
        if args and kwargs:
            raise AssertionError("Only positional or keyword args are allowed")

        self.params: tuple[object, ...] | dict[str, object] = args or kwargs

def __init__(self, addendum: str | None, join: str = "", indents: int = 0) -> None:
        from pandas.errors import Pandas4Warning

        warnings.warn(
            "Appender is deprecated and will be removed in a future version.",
            Pandas4Warning,
            stacklevel=find_stack_level(),
        )
        if indents > 0:
            self.addendum = indent(addendum, indents=indents)
        else:
            self.addendum = addendum
        self.join = join

